class Solution:
    def numEquivDominoPairs(self, dominoes):
        count = 0
        n = len(dominoes)
        def key(d):
            return (d[0], d[1]) if d[0] <= d[1] else (d[1], d[0])
        for i in range(n):
            for j in range(i + 1, n):
                if key(dominoes[i]) == key(dominoes[j]):
                    count += 1
        return count

