class Solution:
    def numEquivDominoPairs(self, dominoes):
        from collections import Counter
        freq = Counter()
        for a, b in dominoes:
            freq[(a, b) if a <= b else (b, a)] += 1
        return sum(c * (c - 1) // 2 for c in freq.values())

