var numEquivDominoPairs = function(dominoes) {
    const freq = new Map();
    for (const [a, b] of dominoes) {
        const key = a <= b ? a * 10 + b : b * 10 + a;
        freq.set(key, (freq.get(key) || 0) + 1);
    }
    let total = 0;
    for (const c of freq.values()) total += (c * (c - 1)) / 2;
    return total;
};
